parameters.jsCode:
const state = $json.state ?? $json;

const materials = Array.isArray(state.finish_materials)
  ? state.finish_materials
  : [];

const headers = [
  'Material',
  'Unit',
  'Supplied By',
  'Unit Price',
  'Quantity',
  'Total Price',
  'Specs / Model',
  'Purchase Link',
  'Ordered?',
  'Status',
  'Notes',
];

const row = (values) => ({
  values: values.map((value) => {
    if (typeof value === 'number') {
      return { userEnteredValue: { numberValue: value } };
    }

    if (typeof value === 'string' && value.startsWith('=')) {
      return { userEnteredValue: { formulaValue: value } };
    }

    return { userEnteredValue: { stringValue: String(value ?? '') } };
  }),
});

const spreadsheet_body = {
  properties: {
    title: state.fm_sheet_name,
  },
  sheets: [
    {
      properties: {
        title: 'Materials',
      },
      data: [
        {
          startRow: 0,
          startColumn: 0,
          rowData: [
            row(headers),
            ...materials.map((m, i) =>
              row([
                m.material,
                m.measure,
                'By Client',
                Number(m.unit_price || 0),
                Number(m.qty || 0),
                `=D${i + 2}*E${i + 2}`,
                m.specs_model,
                m.purchase_link,
                '',
                'Not ordered',
                m.notes,
              ])
            ),
          ],
        },
      ],
    },
  ],
};

return [
  {
    json: {
      ...$json,
      spreadsheet_body,
    },
  },
];
